            errors.append(error("email", "invalid_domain_label", "Email domain contains an invalid label."))
        if label.startswith("-") or label.endswith("-"):
            errors.append(error("email", "invalid_domain_label", "Email domain labels cannot start or end with hyphens."))

    normalized = f"{local}@{ascii_domain}"

    if not EMAIL_RE.match(normalized):
        errors.append(error("email", "invalid_format", "Email format is invalid."))

    if ascii_domain in DISPOSABLE_DOMAINS:
        errors.append(error("email", "disposable_domain", "Disposable email addresses are not allowed."))

    if has_mixed_scripts(unicode_domain):
        errors.append(error("email", "mixed_script_domain", "Email domain uses suspicious mixed scripts."))

    try:
        dns.resolver.resolve(ascii_domain, "MX")
    except Exception:
        try:
            dns.resolver.resolve(ascii_domain, "A")
        except Exception:
            errors.append(error("email", "domain_unreachable", "Email domain does not accept mail."))

    return normalized, ascii_domain, errors


def validate_username(value: str) -> tuple[str | None, str | None, list[dict[str, str]]]:
    errors = []
    username = normalize_text(value).casefold()

    if len(username) < 3:
        errors.append(error("username", "too_short", "Username must be at least 3 characters."))
    if len(username) > 30:
        errors.append(error("username", "too_long", "Username must be 30 characters or fewer."))
    if not USERNAME_RE.match(username):
        errors.append(error("username", "invalid_chars", "Username may contain lowercase letters, numbers, underscores, dots, and hyphens only."))
    if username.startswith((".", "-", "_")) or username.endswith((".", "-", "_")):
        errors.append(error("username", "invalid_edge_char", "Username cannot start or end with punctuation."))
    if ".." in username or "__" in username or "--" in username:
        errors.append(error("username", "repeated_punctuation", "Username cannot contain repeated punctuation."))
    if username in RESERVED_USERNAMES:
        errors.append(error("username", "reserved", "Username is unavailable."))
    if any(term in username for term in OFFENSIVE_TERMS):
        errors.append(error("username", "offensive", "Username is unavailable."))
    if has_mixed_scripts(username):
        errors.append(error("username", "mixed_script", "Username uses suspicious mixed scripts."))

    skeleton = username_skeleton(username)
    if skeleton != username:
        errors.append(error("username", "confusable", "Username contains visually confusable characters."))

    return username, skeleton, errors


def validate_display_name(value: str) -> tuple[str | None, list[dict[str, str]]]:
    errors = []
    display_name = normalize_text(value)

    if len(display_name) < 1:
        errors.append(error("display_name", "required", "Display name is required."))
    if len(display_name) > 80:
        errors.append(error("display_name", "too_long", "Display name must be 80 characters or fewer."))
    if "<" in display_name or ">" in display_name or "&" in display_name:
        errors.append(error("display_name", "unsafe_chars", "Display name contains unsafe characters."))
    if not DISPLAY_NAME_ALLOWED.match(display_name):
        errors.append(error("display_name", "invalid_chars", "Display name contains unsupported characters."))
    if has_mixed_scripts(display_name):
        errors.append(error("display_name", "mixed_script", "Display name uses suspicious mixed scripts."))

    return display_name, errors


def validate_password(password: str, email: str | None, username: str | None, display_name: str | None) -> list[dict[str, str]]:
    errors = []

    if len(password) < 12:
        errors.append(error("password", "too_short", "Password must be at least 12 characters."))
    if len(password) > 128:
        errors.append(error("password", "too_long", "Password must be 128 characters or fewer."))
    if password != password.strip():
        errors.append(error("password", "edge_whitespace", "Password cannot start or end with whitespace."))
    if "\x00" in password:
        errors.append(error("password", "null_byte", "Password cannot contain null bytes."))

    classes = [
        any(ch.islower() for ch in password),
        any(ch.isupper() for ch in password),
        any(ch.isdigit() for ch in password),
        any(not ch.isalnum() for ch in password),
    ]
    if sum(classes) < 3:
        errors.append(error("password", "complexity", "Password must include at least 3 of: lowercase, uppercase, number, symbol."))

    if len(set(password)) < 6:
        errors.append(error("password", "low_variety", "Password must contain more unique characters."))

    if re.search(r"(.)\1{3,}", password):
        errors.append(error("password", "repeated_chars", "Password has too many repeated characters."))

    lowered = password.casefold()
    if lowered in COMMON_PASSWORDS:
        errors.append(error("password", "common", "Password is too common."))

    digest = hashlib.sha1(password.encode("utf-8")).hexdigest().upper()
    if digest in {
        # Example local denylist entry. In production, use k-anonymity HaveIBeenPwned range API
        # or an offline breached-password corpus.
        "CBFDAAC6008F9CAB4083784CBD1874F76618D2A97",
    }:
        errors.append(error("password", "breached", "Password appears in a breached-password corpus."))

    comparable = [username or "", display_name or ""]
    if email:
        comparable.extend(email.split("@", 1))

    for item in comparable:
        item = item.casefold().strip()
        if item and len(item) >= 3 and item in lowered:
            errors.append(error("password", "contains_personal_info", "Password must not contain your email, username, or display name."))
            break

    return errors


def constant_time_dummy_work() -> None:
    try:
        ph.hash("dummy-password-for-timing-equalization")
    except HashingError:
        pass


def validate_payload(payload: RegisterPayload) -> tuple[dict[str, str], list[dict[str, str]]]:
    errors = []
    out = {}

    for field in ("email", "username", "password", "display_name"):
        value = getattr(payload, field)
        if value is None:
            errors.append(error(field, "required", f"{field} is required."))
        elif not isinstance(value, str):
            errors.append(error(field, "type", f"{field} must be a string."))

    if errors:
        return out, errors

    email_value, domain, email_errors = normalize_email(payload.email)
    username, skeleton, username_errors = validate_username(payload.username)
    display_name, display_errors = validate_display_name(payload.display_name)
    password_errors = validate_password(payload.password, email_value, username, display_name)

    errors.extend(email_errors)
    errors.extend(username_errors)
    errors.extend(display_errors)
    errors.extend(password_errors)

    out.update({
        "email": email_value or "",
        "email_domain": domain or "",
        "username": username or "",
        "username_skeleton": skeleton or "",
        "password": payload.password,
        "display_name": display_name or "",
    })

    return out, errors


@app.post("/api/register")
async def register(request: Request, payload: RegisterPayload):
    rate_limited = check_rate_limit(request)
    if rate_limited:
        return rate_limited

    if request.headers.get("content-type", "").split(";")[0].lower() != "application/json":
        return JSONResponse(
            status_code=415,
            content={"errors": [{"field": "request", "code": "unsupported_media_type", "message": "Content-Type must be application/json."}]},
        )

    clean, errors = validate_payload(payload)
    if errors:
        constant_time_dummy_work()
        return JSONResponse(status_code=422, content={"errors": errors})

    now = int(time.time())

    try:
        password_hash = await asyncio.to_thread(ph.hash, clean["password"])
    except HashingError:
        return JSONResponse(
            status_code=500,
            content={"errors": [{"field": "server", "code": "hashing_failed", "message": "Registration could not be completed."}]},
        )

    try:
        with db() as con:
            existing = con.execute(
                "SELECT email FROM users WHERE email = ?",
                (clean["email"],),
            ).fetchone()

            if existing and hmac.compare_digest(existing["email"], clean["email"]):
                constant_time_dummy_work()
                return JSONResponse(
                    status_code=201,
                    content={"message": "If this email can be registered, an account has been created."},
                )

            username_taken = con.execute(
                "SELECT 1 FROM users WHERE username = ? OR username_skeleton = ?",
                (clean["username"], clean["username_skeleton"]),
            ).fetchone()

            if username_taken:
                return JSONResponse(
                    status_code=409,
                    content={
                        "errors": [
                            {
                                "field": "username",
                                "code": "unavailable",
                                "message": "Username is unavailable.",
                            }
                        ]
                    },
                )

            con.execute(
                """
                INSERT INTO users (
                    email, email_domain, username, username_skeleton,
                    display_name, password_hash, created_at, updated_at
                )
                VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                """,
                (
                    clean["email"],
                    clean["email_domain"],
                    clean["username"],
                    clean["username_skeleton"],
                    clean["display_name"],
                    password_hash,
                    now,
                    now,
                ),
            )

    except sqlite3.IntegrityError:
        # Handles concurrent duplicate signups without leaking registered email status.
        constant_time_dummy_work()
        return JSONResponse(
            status_code=201,
            content={"message": "If this email can be registered, an account has been created."},
        )

    return JSONResponse(
        status_code=201,
        content={"message": "If this email can be registered, an account has been created."},
    )


